package cli

import (
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"time"

	"github.com/spf13/cobra"

	"github.com/agent-sync/agent-sync/internal/engine"
	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/report"
)

// hookSkippedMarker records that a git-hook-driven sync yielded to an
// in-progress manual sync (so it never breaks `git pull`).
const hookSkippedMarker = ".agent-sync/state/hook-skipped"

// postMergeRunLockTimeout caps how long a --post-merge (git-hook) sync waits
// for the per-workspace run lock before yielding a blocked result and exiting
// 0. Short so a contended `git pull` is never stalled by the default multi-minute
// wait.
const postMergeRunLockTimeout = 3 * time.Second

func newSyncCommand(deps RootDeps) *cobra.Command {
	var (
		bestEffort      bool
		adoptPrefixes   []string
		targetFilter    []string
		expectDeletions int
		postMerge       bool
		userScope       bool
	)

	cmd := &cobra.Command{
		Use:   "sync",
		Short: "Sync target tools from the canonical manifest",
		Long: "Materialize the canonical source, run each target's adapter, and " +
			"atomically write the resulting configuration into the workspace.",
		SilenceUsage:  true,
		SilenceErrors: true,
		RunE: func(cmd *cobra.Command, _ []string) error {
			rc, err := mustRuntime(cmd)
			if err != nil {
				return err
			}
			now := deps.now()()

			opts := engine.Options{
				AdoptPrefixes: adoptPrefixes,
				TargetsFilter: targetFilter,
				Now:           func() time.Time { return now },
				Logger:        rc.Logger,
			}
			if bestEffort {
				opts.Mode = report.ModeBestEffort
			} else {
				opts.Mode = report.ModeAtomic
			}
			if cmd.Flags().Changed("expect-deletions") {
				opts.ExpectDeletions = &expectDeletions
			}
			if postMerge {
				// A git-hook sync must yield fast to a manual sync rather than
				// stall `git pull`: cap the run-lock wait so contention becomes a
				// quick blocked-and-yield (exit 0) instead of the multi-minute
				// default. The engine reports blocked targets; the post-merge
				// handlers below turn that into a clean exit 0.
				opts.RunLockTimeout = postMergeRunLockTimeout
			}

			// An explicit --workspace override pins a single scope and disables
			// hierarchy discovery (today's behavior wins). --user is meaningless
			// then: it selects the user scope of a discovered hierarchy.
			if rc.Flags.Workspace != "" {
				if userScope {
					return errUserWithWorkspace
				}
				return runSingleScopeSync(cmd, rc, opts, postMerge, now)
			}

			// Hierarchy path: discover every emit scope from cwd and sync each.
			cwd, err := os.Getwd()
			if err != nil {
				return fmt.Errorf("sync: resolve cwd: %w", err)
			}
			home, err := resolveHome()
			if err != nil {
				return fmt.Errorf("sync: %w", err)
			}
			outcomes, err := runHierarchySync(cmd.Context(), rc, cwd, home,
				hierarchySyncOptions{IncludeUser: userScope, EngineOpts: opts}, now)
			if err != nil {
				return fmt.Errorf("sync: %w", err)
			}

			// Post-merge hook mode: if any scope was blocked by an in-progress
			// sync's lock, write that scope's skip marker and exit 0 so
			// `git pull` is never broken (plan U3 / AGENTS invariant #3 spirit).
			if postMerge {
				if handled := handleHierarchyPostMerge(rc, outcomes, now); handled {
					return nil
				}
			}

			if rc.Access.Output == OutputJSON {
				if err := renderHierarchyJSON(cmd.OutOrStdout(), outcomes); err != nil {
					return err
				}
			} else if err := renderHierarchyText(cmd.OutOrStdout(), outcomes); err != nil {
				return err
			}
			if code := hierarchyExitCode(outcomes); code != 0 {
				return &exitError{code: code, err: errors.New("sync reported failures")}
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&bestEffort, "best-effort", false, "continue past a failing target instead of aborting the run")
	cmd.Flags().StringArrayVar(&adoptPrefixes, "adopt-prefix", nil, "adopt pre-existing unmanaged content under this reserved prefix")
	cmd.Flags().StringArrayVar(&targetFilter, "target", nil, "restrict the sync to these target names (repeatable)")
	cmd.Flags().IntVar(&expectDeletions, "expect-deletions", 0, "abort unless exactly this many files would be deleted")
	cmd.Flags().BoolVar(&postMerge, "post-merge", false, "git-hook mode: yield to an in-progress sync and exit 0")
	cmd.Flags().BoolVar(&userScope, "user", false, "also sync the user-level (~) manifest")
	return cmd
}

// runSingleScopeSync runs the legacy single-scope sync against the nearest
// (or explicit --workspace) scope. It preserves today's behavior verbatim and
// is taken only when an explicit --workspace override is in effect; the
// default path is the hierarchy orchestrator. validate also relies on this
// single-scope shape via prepareEngine.
func runSingleScopeSync(cmd *cobra.Command, rc *runtimeContext, opts engine.Options, postMerge bool, now time.Time) error {
	prep, err := prepareEngine(cmd.Context(), rc, now)
	if err != nil {
		return fmt.Errorf("sync: %w", err)
	}
	defer prep.Close()

	req := prep.Request
	req.Options = opts

	root := prep.Root
	summary, err := engine.Sync(cmd.Context(), req)
	if err != nil {
		return fmt.Errorf("sync: %w", err)
	}

	// Post-merge hook mode: if a target was blocked by an in-progress sync's
	// lock, write the skip marker and exit 0 so `git pull` is never broken
	// (plan U3 / AGENTS invariant #3 spirit).
	if postMerge && anyBlocked(summary) {
		if werr := writeHookSkipped(root, now); werr != nil {
			rc.Logger.Warn("sync: failed to write hook-skipped marker", "err", werr)
		}
		return nil
	}

	if err := renderSummary(cmd, rc.Access, summary); err != nil {
		return err
	}
	if summary.Outcome.ExitCode != 0 {
		return &exitError{code: summary.Outcome.ExitCode, err: errors.New("sync reported failures")}
	}
	return nil
}

// handleHierarchyPostMerge applies the post-merge yield across the hierarchy:
// for each scope whose sync was blocked by an in-progress lock, it writes that
// scope's hook-skipped marker. It returns true when any scope was blocked, in
// which case the caller exits 0 so `git pull` is never broken. A blocked scope
// has no engine error (the lock yield is a clean outcome), so its summary is
// inspected via anyBlocked.
func handleHierarchyPostMerge(rc *runtimeContext, outcomes []scopeOutcome, now time.Time) bool {
	handled := false
	for _, o := range outcomes {
		if o.Err != nil || !anyBlocked(o.Summary) {
			continue
		}
		handled = true
		root, err := fsroot.OpenWorkspaceRoot(o.Scope.Root)
		if err != nil {
			rc.Logger.Warn("sync: failed to open root for hook-skipped marker", "root", o.Scope.Root, "err", err)
			continue
		}
		if werr := writeHookSkipped(root, now); werr != nil {
			rc.Logger.Warn("sync: failed to write hook-skipped marker", "root", o.Scope.Root, "err", werr)
		}
		_ = root.Close()
	}
	return handled
}

func anyBlocked(s report.Summary) bool {
	for _, t := range s.Targets {
		if t.Status == report.StatusBlocked {
			return true
		}
	}
	return false
}

func writeHookSkipped(root *fsroot.Root, now time.Time) error {
	if err := root.Inner().MkdirAll(filepath.Dir(hookSkippedMarker), 0o755); err != nil {
		return err
	}
	return root.StagedWrite(hookSkippedMarker, []byte(now.UTC().Format(time.RFC3339)+"\n"), 0o644)
}

// renderSummary writes the report to stdout as text or JSON per the
// resolved Access; logs and banners go to stderr (the logger), data to
// stdout.
func renderSummary(cmd *cobra.Command, access Access, summary report.Summary) error {
	if access.Output == OutputJSON {
		data, err := report.MarshalJSON(summary)
		if err != nil {
			return fmt.Errorf("sync: marshal json: %w", err)
		}
		_, err = fmt.Fprintln(cmd.OutOrStdout(), string(data))
		return err
	}
	_, err := fmt.Fprint(cmd.OutOrStdout(), report.RenderText(summary))
	return err
}

	// misleading — the rule DOES take effect, via the project. Under `sync
	// --user` the user scope is emitted (and carries that warning), so drop just
	// that one warning from its outcome when composition fired this run. The
	// agents-md user warning is not composed and stays. Composition-off runs are
	// untouched. Caller-side filter keeps coverage.Analyze pure.
	if composeActive {
		for i := range outcomes {
			if outcomes[i].Scope.Level == hierarchy.LevelUser {
				outcomes[i].Warnings = dropWarning(outcomes[i].Warnings, cursorTarget, ir.KindRule, hierarchy.LevelUser)
			}
		}
	}
	return outcomes, nil
}

// dropWarning returns ws without any warning matching (target, kind, level).
// Used to suppress the user-scope Cursor rule warning when composition makes it
// misleading (U5). The input slice is not mutated.
func dropWarning(ws []coverage.Warning, target string, kind ir.Kind, level hierarchy.Level) []coverage.Warning {
	out := make([]coverage.Warning, 0, len(ws))
	for _, w := range ws {
		if w.Target == target && w.Kind == kind && w.Level == level {
			continue
		}
		out = append(out, w)
	}
	return out
}

// applyCursorComposition folds the user-scope Cursor rule layer into a
// project-scope request when the project manifest opts in. It is the single
// composition entry point shared by the hierarchy sync loop AND the single-scope
// path (validate, watch, sync --workspace), so every command that builds a
// project request sees the same composed desired state. Without this, a composed
// project would report false `WouldDelete` drift under validate and lose its
// composed rules under watch / --workspace sync (the owned-subdir swap wipes
// anything not in the freshly-staged set).
//
// It mutates req in place and returns whether rules were composed. All paths are
// gated on m.Compose.CursorRulesFromUser:
//   - scope != project: composition is project-only (D1) — warn that the opt-in
//     has no effect at this scope, return false.
//   - cursor not a target, or no user manifest at home: silent no-op, false.
//   - user source unreadable: defer cursor (drop it from req.Targets) so a
//     transient failure can't wipe previously-composed rules; warn; false.
//   - rules composed: append to req.Nodes; true.
func applyCursorComposition(ctx context.Context, rc *runtimeContext, req *engine.Request, m *manifest.Manifest, scope, home string, now time.Time) bool {
	if !m.Compose.CursorRulesFromUser {
		return false
	}
	if scope != hierarchy.LevelProject.String() {
		// Directory/user manifest set the opt-in; composition only applies at
		// project scope. Warn so it isn't a silent no-op.
		rc.Logger.Warn("compose: cursor-rules-from-user has no effect at this scope; set it on the project manifest", "scope", scope)
		return false
	}
	if !slices.Contains(req.Targets, cursorTarget) {
		return false
	}
	user, ok := hierarchy.UserScope(home)
	if !ok {
		return false // no user manifest to compose from
	}
	composed, failed := composeUserRules(ctx, rc, user, cursorRuleIDsOf(req.Nodes), now)
	switch {
	case failed:
		// The user source could not be read this run (offline URL, malformed user
		// manifest). Defer the Cursor sync rather than syncing project-only rules:
		// .cursor/rules/agent-sync/ is an owned subdir replaced by a wholesale
		// swap, so a project-only sync would wipe the previously-composed rules.
		// Dropping cursor from this run's targets leaves that subdir untouched; the
		// next sync that can read the user source re-syncs cursor fully. Project
		// cursor rule edits wait for that run — the conservative, data-preserving
		// choice (plan D8, transient-failure guard).
		req.Targets = withoutTarget(req.Targets, cursorTarget)
		rc.Logger.Warn("compose: deferring cursor this run — user source unreadable; existing .cursor/rules left intact",
			"user_manifest", user.ManifestPath)
		return false
	case len(composed) > 0:
		req.Nodes = append(req.Nodes, composed...)
		return true
	}
	return false
}

// composeUserRules materializes the user-scope manifest read-only and returns
// its Cursor `rule` nodes for injection into a project sync (plan D1). The
// project root remains the only write target; the user root is opened solely to
// read IR.
//
// It is best-effort (plan D8): any failure — load, open, materialize, offline
// or uncached remote source, decode — yields nil plus a warning and never
// propagates. A project sync must not fail, block on a trust prompt, or hit the
// network because of the user's global manifest. Remote (URL) user sources are
// materialized OFFLINE (cache-only) so composition never fetches; a user who
// wants a remote source composed pre-populates the cache with `sync --user`.
//
// projectRuleIDs is the set of `rule` ids already present in the project scope.
// A user rule whose id collides is dropped (project wins, matching Cursor's
// Team>Project>User precedence) with a per-id warning: the id namespace is flat,
// so a coincidental clash must be observable rather than a silent data loss.
//
// The returned failed flag distinguishes "could not read the user source"
// (load/open/materialize error → failed=true) from "read fine, produced zero
// composable rules" (failed=false). The caller defers the whole Cursor sync when
// failed, so a transient read failure (offline URL, malformed user manifest)
// leaves the previously-composed rules in the owned .cursor/rules/ subdir intact
// rather than letting the subdir swap wipe them — see the deferral at the call
// site (plan D8, transient-failure guard).
func composeUserRules(ctx context.Context, rc *runtimeContext, user hierarchy.Scope, projectRuleIDs map[string]struct{}, now time.Time) (nodes []ir.Node, failed bool) {
	// Deliberately NOT prepareScope: this reads user IR only. prepareScope also
	// runs DiscoverAdapters (which can launch adapter subprocesses) and builds a
